INSERT INTO products (id, category_id, name, description, price, stock_quantity, rating, num_reviews, specifications) VALUES
(380, 38, 'Boldfit Polyester Blend Sports Head Band', 'Breathable, non-slip & quick-drying gym hair band for men & women. Perfect for workouts and running.', 199.00, 300, 4.3, 4200, '{"Material": "Polyester Blend", "Gender": "Unisex", "Purpose": "Gym/Running", "Brand": "Boldfit"}'),
(381, 38, 'Lotus Herbals Safe Sun Sports Sunscreen SPF 70 PA+++, 80g', 'High-protection sweat & waterproof sports sunscreen. Preservative-free formula for dry skin.', 399.00, 150, 4.4, 2800, '{"Volume": "80g", "SPF": "70 PA+++", "Skin Type": "Dry Skin", "Brand": "Lotus Herbals", "Feature": "Sweat & Waterproof"}'),
(382, 38, 'Rexona Sport Defence Roll-On Deodorant for Men, 50ml', 'Underarm protection deodorant built for sport. Keeps you fresh through intense activity.', 219.00, 200, 4.3, 3100, '{"Volume": "50ml", "Type": "Roll-On", "Gender": "Men", "Brand": "Rexona", "Focus": "Sport"}'),
(383, 38, 'Mannlich Anti Chafing Cream for Men, 50ml', 'Anti-rash cream for intimate areas. Reduces inner thigh rashes from sports. Dermatologically tested.', 349.00, 100, 4.4, 980, '{"Volume": "50ml", "Type": "Anti-Chafing Cream", "Brand": "Mannlich", "Tested": "Dermatologically"}'),
(384, 38, 'SignoraWare Shake N Shake Stainless Steel Shaker, 650ml (Blue)', 'Leakproof shaker with measurement markings. Perfect for protein shakes & pre-workout formulas.', 599.00, 120, 4.5, 1750, '{"Capacity": "650ml", "Material": "Stainless Steel", "Color": "Blue", "Brand": "SignoraWare", "Feature": "Leakproof"}'),
(385, 38, 'Cello Beatle Stainless Steel Sports Bottle, 700ml (Blue)', 'Sturdy stainless steel sports water bottle – great for gym, cycling, and outdoor use.', 449.00, 180, 4.3, 2200, '{"Capacity": "700ml", "Material": "Stainless Steel", "Color": "Blue", "Brand": "Cello"}'),
(386, 38, 'ElectroFizz Isotonic Energy Drink Powder, 1 Kg (7 Berries)', 'Isotonic energy drink for endurance sports. Replenishes electrolytes fast during intense activity.', 799.00, 80, 4.5, 1600, '{"Weight": "1 Kg", "Flavour": "7 Berries", "Type": "Isotonic Energy", "Brand": "ElectroFizz", "Servings": "~100"}'),
(387, 38, 'Vector X Ultra PVC Football Size 5, White', 'Machine-stitched 32-panel futsal football. Water-resistant with SR Bladder. For match and training.', 699.00, 100, 4.4, 3400, '{"Size": "5", "Color": "White", "Bladder": "SR", "Stitching": "Machine", "Material": "PVC", "Brand": "Vector X"}'),
(388, 38, 'Vector X Ultra PVC Football Size 5, Black', 'Machine-stitched 32-panel futsal football. Water-resistant with SR Bladder. For adults 15+ years.', 699.00, 100, 4.4, 2900, '{"Size": "5", "Color": "Black", "Bladder": "SR", "Stitching": "Machine", "Material": "PVC", "Brand": "Vector X"}'),
(389, 38, 'Vector X Street Soccer Football Size 3, Red (Kids)', 'Rubberised hand-stitched football with Latex Bladder. Water-resistant. Ideal for kids 6-10 years.', 499.00, 80, 4.3, 1800, '{"Size": "3", "Color": "Red", "Bladder": "Latex", "Stitching": "Hand", "For": "Kids 6-10 Yrs", "Brand": "Vector X"}'),
(390, 38, 'SkinEasi Activ Silicone Anti-Chafing Gel, 20g', 'Transparent silicone gel that prevents skin chafing. Great for runners, cyclists, and gym athletes.', 299.00, 150, 4.5, 2100, '{"Weight": "20g", "Type": "Anti-Chafing Gel", "Material": "Silicone", "Brand": "Amaterasu / SkinEasi"}'),
(391, 38, 'Vector X Sonic PU Football Size 5, White-Yellow', 'Hand-stitched 32-panel PU football with Latex Bladder. Designed for match and training play.', 849.00, 70, 4.5, 1500, '{"Size": "5", "Color": "White-Yellow", "Bladder": "Latex", "Stitching": "Hand", "Material": "PU", "Brand": "Vector X"}'),
(392, 38, 'ElectroFizz Electrolyte Powder with Probiotics, 1 Kg (Lemon)', 'Instant electrolyte drink with Probiotics & Vitamin C. 100 servings – great for workout hydration.', 749.00, 90, 4.4, 2000, '{"Weight": "1 Kg", "Flavour": "Lemon", "Brand": "ElectroFizz", "Servings": "100", "Extras": "Probiotics, Vitamin C"}'),
(393, 38, 'Vector X Roma Synthetic Football Size 5, Yellow', 'Hand-stitched 32-panel synthetic rubber football. Water-resistant with Latex Bladder for outdoor play.', 749.00, 75, 4.4, 1200, '{"Size": "5", "Color": "Yellow", "Bladder": "Latex", "Stitching": "Hand", "Material": "Synthetic Rubber", "Brand": "Vector X"}'),
(394, 38, 'ElectroFizz Electrolyte Powder with Probiotics, 1 Kg (Red Guava)', 'Instant electrolyte drink mix with Vitamin C and Probiotics. 100 servings for sustained hydration.', 749.00, 85, 4.4, 1700, '{"Weight": "1 Kg", "Flavour": "Red Guava", "Brand": "ElectroFizz", "Servings": "100", "Extras": "Probiotics, Vitamin C"}'),
(395, 38, 'Vector X Impulse Thermo-Fused Football Size 5, Red', 'Rubberised thermo-fused football with Butyl Bladder. Durable, water-resistant. For adults 15+.', 899.00, 60, 4.5, 980, '{"Size": "5", "Color": "Red", "Bladder": "Butyl", "Construction": "Thermo Fused", "Brand": "Vector X"}'),
(396, 38, 'Vector X Impulse Thermo-Fused Football Size 5, White', 'Rubberised thermo-fused football with Butyl Bladder. Comes with a free air needle. Size 5.', 899.00, 60, 4.5, 870, '{"Size": "5", "Color": "White", "Bladder": "Butyl", "Construction": "Thermo Fused", "Brand": "Vector X"}'),
(397, 38, 'ElectroFizz Electrolyte Powder with Probiotics, 1 Kg (Green Apple)', 'Instant electrolyte drink with Probiotics & Vitamin C. Refreshing green apple flavour, 100 servings.', 749.00, 80, 4.4, 1400, '{"Weight": "1 Kg", "Flavour": "Green Apple", "Brand": "ElectroFizz", "Servings": "100", "Extras": "Probiotics, Vitamin C"}'),
(398, 38, 'Cramp A-salt Electrolyte Powder Mix, 30 Sticks (Orange)', 'Sodium, Potassium, Magnesium & Coconut Water electrolyte blend. Zero sugar, endurance-focused hydration.', 699.00, 100, 4.6, 1100, '{"Count": "30 Sticks", "Flavour": "Orange", "Brand": "Cramp A-salt", "Sugar": "Zero", "Key Minerals": "Na, K, Mg + Coconut Water"}');
